#             ],
#             "Resource": "*"
#         },
#         {
#             "Effect": "Allow",
#             "Action": [
#                 "s3:GetObject",
#                 "s3:PutObject"
#             ],
#             "Resource": "arn:aws:s3:::your-bucket-name/*"
#         },
#         {
#             "Effect": "Allow",
#             "Action": [
#                 "sns:Publish"
#             ],
#             "Resource": "arn:aws:sns:::your-sns-topic-arn"
#         }
#     ]
# }

def lambda_handler(event, context):
    try:
        # Get S3 bucket name and object key from event
        bucket_name = event['Records'][0]['s3']['bucket']['name']
        object_key = event['Records'][0]['s3']['object']['key']

        # Read image from S3
        image_data = s3.get_object(Bucket=bucket_name, Key=object_key)['Body'].read()

        # Send notification via SNS (assuming you have a topic set up)
        sns.publish(
            TopicArn='arn:aws:sns:::your-sns-topic-arn',
            Message=image_data,
            Subject='New Image Uploaded'
        )

        # Log to CloudWatch
        logging.getLogger().info('Image processed successfully')
    except NoCredentialsError:
        print("Credentials not found")
    except Exception as e:
        logging.getLogger().error(str(e))
        return {
            'statusCode': 500,
            'body': str(e)
        }

    # Return success response
    return {
        'statusCode': 200
    }